#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        if(N % 4 == 1) printf("Bhima\n");
        else printf("Arjuna\n");
    }
    return 0;
}

